def mystery(x):
    if type(x) is not str:
        return False
    if len(x) != 6:
        return False

    # Pattern: digit-letter-digit-letter-digit-letter
    for i in [0, 2, 4]:
        if not x[i].isdigit():
            return False
    for i in [1, 3, 5]:
        if not x[i].isupper():
            return False

    # Extract digits and letters
    digits = [int(x[i]) for i in [0, 2, 4]]
    letters = [x[i] for i in [1, 3, 5]]

    # Digits must form an arithmetic sequence with positive difference
    diff = digits[1] - digits[0]
    if digits[2] - digits[1] != diff or diff <= 0:
        return False

    # Letters must form pattern XYX (first and last same)
    if letters[0] != letters[2]:
        return False

    # Sum of digits must equal sum of letter positions (A=1, B=2, ..., Z=26)
    digit_sum = sum(digits)
    letter_sum = sum(ord(c) - ord('A') + 1 for c in letters)

    if digit_sum != letter_sum:
        return False

    return True

