    if not isinstance(x, str):
        return False
    if len(x) != 4:
        return False

    # All lowercase letters
    if not x.islower():
        return False

    # All characters must be distinct
    if len(set(x)) != 4:
        return False

    # When sorted, characters must form an arithmetic sequence of ASCII values
    sorted_x = sorted(x)
    ascii_vals = [ord(c) for c in sorted_x]

    diff = ascii_vals[1] - ascii_vals[0]
    if ascii_vals[2] - ascii_vals[1] != diff:
        return False
    if ascii_vals[3] - ascii_vals[2] != diff:
        return False

    # The string must be a rotation of its sorted form
    sorted_doubled = sorted_x + sorted_x
    if x not in sorted_doubled:
        return False

    # First character must come before last character alphabetically
    if x[0] >= x[-1]:
        return False

    return True
